const e=`{% block sw_notification_center_item %} <div class="sw-notification-center-item"> {% block sw_notification_center_item_header %} <div class="sw-notification-center-item__header" :class="itemHeaderClass" > <div class="sw-notification-center-item__header-left"> <div v-if="!notification.visited" class="sw-notification-center-item__header-dot" ></div> {% block sw_notification_center_item_header_title %} <p class="sw-notification-center-item__title"> {{ $te(notification.title) ? $t(notification.title) : notification.title }} </p> {% endblock %} </div> <div class="sw-notification-center-item__header-right"> {% block sw_notification_center_item_header_timestamp %} <p class="sw-notification-center-item__timestamp"> <sw-time-ago :date="notification.timestamp" :date-time-format="{ month: '2-digit', day: '2-digit' }" /> </p> {% endblock %} {% block sw_notification_center_item_header_delete %} <mt-icon class="sw-notification-center-item__delete" name="regular-times-s" size="12px" @click.stop="onDelete" /> {% endblock %} </div> </div> {% endblock %} {% block sw_notification_center_item_content %} <div class="sw-notification-center-item__content"> {% block sw_notification_center_item_content_message %} <p class="sw-notification-center-item__message" v-html="$sanitize($te(notification.message) ? $t(notification.message) : notification.message, { ALLOWED_TAGS: ['a', 'b', 'i', 'u', 'strong', 'em', 'br'], ALLOWED_ATTR: ['href', 'target'] })" ></p> {% endblock %} {% block sw_notification_center_item_loader %} <sw-loader v-if="notification.isLoading" class="sw-notification-center-item__loader" size="12px" /> {% endblock %} </div> {% endblock %} {% block sw_notification_center_item_actions %} <div v-if="notification.actions" class="sw-notification-center-item__actions" > {% block sw_notification_center_item_actions_inner %} <template v-for="action in notificationActions" :key="action.label" > {% block sw_notification_center_item_actions_item_container %} <div class="sw-notification-center-item__actions-item-container"> {% block sw_notification_center_item_actions_item %} <mt-button block size="small" variant="secondary" @click="handleAction(action)" > {{ action.label }} </mt-button> {% endblock %} </div> {% endblock %} </template> {% endblock %} </div> {% endblock %} </div> {% endblock %}`,n={template:e,emits:["center-close"],props:{notification:{type:Object,required:!0}},computed:{itemHeaderClass(){return{"sw-notification-center-item__header--is-new":!this.notification.visited}},notificationActions(){return this.notification.actions.filter(t=>t.route)}},methods:{isNotificationFromSameDay(){const t=this.notification.timestamp,i=new Date;return t.getDate()===i.getDate()&&t.getMonth()===i.getMonth()&&t.getFullYear()===i.getFullYear()},onDelete(){Shopware.Store.get("notification").removeNotification(this.notification)},handleAction(t){if(Shopware.Utils.string.isUrl(t.route)){window.open(t.route);return}this.$router.push(t.route),this.$emit("center-close")}}};export{n as default};
